"""
MKT Original Commentary — Exodus 16–18
Run: python3 scripts/zc-original-exodus-16-18.py

Source data used:
- data/interlinear/exodus.json
- data/translation/draft/mediating/exodus.json

Key decisions in this range:
- Ch16: 'man hu' (what is it?) is the origin of 'manna' — deliberate ambiguity preserved
- Ch16: shabbat appears here for the first time in the narrative Torah, before Sinai
- Ch17: 'rib' (quarrel) is a legal-covenant lawsuit term, not mere bickering
- Ch17: YHWH standing on the rock before Moses strikes signals substitutionary solidarity
- Ch18: Jethro's 'now I know YHWH is greater than all gods' treated as genuine confession
- Ch18: 'horatah' (you shall teach) in v20 is from yarah, the root of torah
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EXODUS_ORIGINAL = {
    "16": {
        "1": "<p><strong>midbar Sin</strong> (<em>midbār Sîn</em>): the Wilderness of Sin — a geographical name, possibly connected to the Sinai peninsula. The narrator dates the arrival precisely: the fifteenth day of the second month, exactly one month after the Passover (Exod 12:6). The liturgical precision signals that the wilderness journey is being measured against YHWH's redemptive calendar.</p>",
        "2": "<p><strong>yillônû</strong> (<em>wayyillônû</em>): 'they grumbled/murmured' — from the root <em>lûn</em>, the technical verb for Israel's wilderness complaint. It appears six times in ch16 alone (vv.2, 7, 8, 9, 12) and becomes the vocabulary of the wilderness rebellion pattern throughout Numbers. Grumbling is addressed to Moses and Aaron but YHWH hears it as directed at himself (v.8).</p>",
        "3": "<p><strong>bĕyad YHWH</strong> ('by the hand of YHWH'): the wilderness generation prefers death in Egypt under YHWH's judgment to uncertain life in the wilderness. The phrase <em>lĕpōt bāśār</em> ('by pots of flesh') is nostalgic hyperbole. The irony is sharp: they want to die 'by the hand of YHWH' when YHWH's hand has just saved them at the sea (14:30-31). The covenant lawsuit begins here: the redeemed people question the goodness of their Redeemer.</p>",
        "4": "<p><strong>māṭîr lākem leḥem min-haššāmayim</strong>: 'I will rain down bread from heaven for you.' The verb <em>māṭar</em> (to rain) is normally used of rain; here it is used of manna — a deliberate atmospheric metaphor establishing the bread as direct provision from YHWH's domain. The phrase <em>leḥem min-haššāmayim</em> (bread from heaven) is quoted verbatim in Ps 78:24. The second clause introduces the test motive: <em>lĕmaʿan ʾănassennû hăyēlēk bĕtôrātî ʾim lōʾ</em> — 'in order that I may test them whether they will walk in my Torah or not.' The manna is a structured test of covenant obedience from the beginning.</p>",
        "5": "<p><strong>miśneh</strong> (<em>mišneh</em>): 'double/twice as much.' On the sixth day the gathering is doubled in anticipation of the seventh day's rest. The same root gives <em>šēnî</em> (second) and <em>šānāh</em> (to repeat). The doubling on the sixth day provides the material basis for Sabbath rest — YHWH's provision anticipates the need before the command is given explicitly.</p>",
        "6": "<p>The paired provision announcement: meat (<em>śĕlāw</em>, quail) in the evening and bread (<em>man</em>, manna) in the morning. The evening-morning sequence is the creation rhythm (Gen 1), and the paired provision demonstrates YHWH's complete provision across the full daily cycle. Moses and Aaron make clear that the murmuring is heard by YHWH, not merely directed at the two human leaders.</p>",
        "7": "<p><strong>kĕbôd YHWH</strong> (<em>kĕbôd Yahweh</em>): 'the glory of YHWH.' The noun <em>kābôd</em> derives from <em>kābed</em> (to be heavy/weighty); glory is the weight or gravitas of God's self-revelation. YHWH's response to complaint is not judgment but demonstration of his character through provision — the provision is itself a glory-display.</p>",
        "8": "<p><strong>lōʾ ʿālênû tĕlunnōtêkem kî ʿal YHWH</strong>: 'your grumblings are not against us but against YHWH.' The theological analysis of complaint: when Israel murmurs against Moses and Aaron, YHWH is the real target. This framing recurs in 1 Sam 8:7 and Luke 10:16 ('whoever rejects you rejects me'). Mediators bear the complaint of the people, but YHWH registers it as directed at himself.</p>",
        "9": "<p><strong>qirĕbû lipnê YHWH</strong>: 'draw near before YHWH.' The verb <em>qārab</em> (to draw near, approach) is the central verb of the sacrificial system — worshipers draw near with offerings; here YHWH himself draws near with provision. The complaint creates the occasion for theophanic encounter.</p>",
        "10": "<p><strong>hinnēh kĕbôd YHWH nirʾāh beʿānān</strong>: 'the glory of YHWH appeared in the cloud.' The cloud (<em>ʿānān</em>) is the vehicle of divine presence throughout the wilderness narrative. <em>Nirʾāh</em> (Niphal of <em>rāʾāh</em>, to appear/be seen) indicates a controlled, mediated revelation — YHWH makes himself visible but in qualified form, not unmediated glory.</p>",
        "11": "<p>YHWH speaks to Moses: the divine word of promise precedes and guarantees the provision. The structure of vv.11-12 follows the established pattern: YHWH speaks to Moses, Moses relays to Israel, the promised event happens. The chain of mediation (YHWH → Moses → people → event) will be formalized at Sinai but is practiced here in the wilderness.</p>",
        "12": "<p><strong>šāmaʿtî ʾet tĕlunnat bĕnê yiśrāʾēl</strong>: 'I have heard the murmuring of the children of Israel.' The phrase <em>wîdaʿtem kî ʾănî YHWH ʾĕlōhêkem</em> ('you shall know that I am YHWH your God') is the recognition formula repeated throughout Ezekiel — the purpose of divine acts is theological knowledge. YHWH provides in order to be known, not merely to satisfy appetite.</p>",
        "13": "<p><strong>śĕlāw</strong> (<em>śĕlāw</em>): quail — a migratory bird (<em>Coturnix coturnix</em>) that crosses Sinai twice yearly; exhausted migrating quail land in large numbers and are easily caught. The Hebrew word appears three times in the Pentateuch (here; Num 11:31-32; Ps 105:40). The provision is naturalistic but timed and organized supernaturally — the ordinary animal is the vehicle of extraordinary provision.</p>",
        "14": "<p><strong>ḥasas dāq mĕḥuspar</strong>: 'fine flakes, like frost.' The manna is described in two paired adjectives: <em>dāq</em> (thin/fine) and <em>mĕḥuspar</em> (small/flake-like). The vocabulary of smallness — delicate, fine, thin — emphasizes the manna's otherness from ordinary grain. It descends with the dew, associated with the created abundance of morning moisture.</p>",
        "15": "<p><strong>man hûʾ</strong>: This two-word phrase is the origin of the word 'manna' and is a studied ambiguity. <em>Man</em> in Aramaic/Hebrew means 'what?' — so <em>man hûʾ</em> is 'what is it?' The narrator preserves both meanings simultaneously: the word for the substance is the question about the substance. Moses's explanation ('it is the bread which YHWH has given you to eat') answers the question without removing the wonder. The name 'manna' is carried through Num 11:6-9, Ps 78:24, and the John 6 Bread of Life discourse.</p>",
        "16": "<p><strong>ʿōmer</strong> (<em>ʿōmer</em>): a dry-measure unit, defined later (v36) as one-tenth of an ephah. This is its first occurrence in Scripture — the unit is only used in the manna narrative. Each person gathers one omer: <em>legulgōlet</em> ('per head,' literally 'per skull') is the counting unit, anticipating the census of Num 1. The provision is democratized — every person receives exactly enough, contrasting with normal food distribution that follows economic and social hierarchies.</p>",
        "17": "<p>The gathering proceeds as commanded but the amounts vary. The phenomenon anticipates the leveling of v18: despite differing quantities gathered, each has exactly what they need. The miracle is not identical individual effort but divinely calibrated distribution — the manna economy points toward 2 Cor 8:15.</p>",
        "18": "<p><strong>hammarbeh lōʾ heydir wĕhammaʿʿîṭ lōʾ ḥiśîr</strong>: 'whoever gathered much had no excess, and whoever gathered little had no lack.' <em>Heydir</em> (surplus/excess) comes from <em>yādar</em> (to remain over); <em>ḥiśîr</em> (lack/deficit) from <em>ḥāsar</em> (to lack). Paul quotes this verse in 2 Cor 8:15 as the principle behind the Jerusalem collection: the Gentile abundance supplies the Jerusalem lack. The manna economy becomes the pattern for the covenant community's economic ethics.</p>",
        "19": "<p><strong>ʾal yôter mimmennû ʾîš ʿad bōqer</strong>: 'let no one leave any of it until morning.' The command against hoarding tests trust: leave nothing overnight, gather fresh each day. YHWH trains his people away from anxiety-driven accumulation toward daily dependence — the structural teaching behind the Lord's Prayer's 'give us today our daily bread' (Matt 6:11).</p>",
        "20": "<p><strong>wayyarūm tôlāʿîm wayyibʾaš</strong>: 'it bred worms and became foul.' Those who disobeyed and kept the manna overnight found it infested and rotting. The contrast with the Sabbath provision (v24) is pointed: what breeds worms on ordinary days remains pure on the Sabbath. The same physical substance behaves differently according to YHWH's covenant calendar — the natural order is subordinated to his decrees.</p>",
        "21": "<p>Daily gathering in the morning until the sun heats the ground, when the manna melts. The provision is neither storable nor indefinitely available — it must be sought each morning in its appointed time. The temporality of the provision enforces the daily rhythm of covenant dependence that YHWH is building into his people's habits.</p>",
        "22": "<p><strong>miśneh leḥem</strong>: 'double bread' — on the sixth day the provision itself doubles before Moses announces the Sabbath principle (v23). YHWH's provision anticipates his own command. The assembly leaders come to Moses concerned; the explanation that follows is the first Sabbath announcement in the narrative Torah.</p>",
        "23": "<p><strong>šabbat šabbātôn qōdeš laYHWH</strong>: 'a Sabbath of complete rest, holy to YHWH.' The phrase <em>šabbat šabbātôn</em> is the absolute-state construction with a cognate noun for intensification — 'Sabbath of Sabbaths' — marking superlative rest. This is the first time <em>šabbāt</em> (Sabbath) appears in the Torah narrative, preceding the Sinai legislation. <em>Qōdeš laYHWH</em> (holy to YHWH) indicates the Sabbath belongs to YHWH's sphere. The Sabbath is revealed in the context of manna provision, not first at Sinai.</p>",
        "24": "<p>The Sabbath provision is confirmed by miracle: the manna kept overnight for the Sabbath does not rot or breed worms (contrast v20). The physical preservation of the Sabbath portion is YHWH's material attestation of the day's holiness — empirical confirmation of the Sabbath command before it has been formally legislated at Sinai (20:8-11).</p>",
        "25": "<p><strong>ʾĕkhuluhû hayyôm kî šabbāt hayyôm laYHWH</strong>: 'eat it today, for today is a Sabbath to YHWH.' The manna is the occasion for the first Sabbath teaching: the structure of the created week — six days of provision, rest on the seventh — is instantiated in daily wilderness life before the Ten Commandments are given. Creation theology (Gen 2:2-3) is embedded in covenant provision.</p>",
        "26": "<p>Six days of gathering; on the seventh, none is to be found. The provision respects the Sabbath by its absence — YHWH will not give manna on the day set apart for rest. The refusal to provide enforces the Sabbath rest structurally: you cannot gather on the Sabbath even if you try, because there is none to gather.</p>",
        "27": "<p>Some go out to gather on the seventh day and find nothing. YHWH's response (v28) — <em>ʿad ʾānāh mēritem</em>, 'how long do you refuse?' — uses the vocabulary of prophetic rebuke. <em>ʿAd ʾānāh</em> (how long?) is the language of Psalms and Prophets addressing chronic disobedience. The Sabbath command is enforced not only by command but by the absence of provision.</p>",
        "28": "<p><strong>miṣwōtay wĕtôrōtāy</strong>: The paired terms: <em>miṣwôt</em> (commandments, specific directives) and <em>tôrôt</em> (plural of <em>tôrāh</em>, instructions/laws). The use of <em>tôrôt</em> (plural) suggests a broader instruction complex already in view, anticipating the full Sinai legislation. The manna narrative functions as a pre-Sinai probationary period — a training ground for covenant obedience before the law is formally given.</p>",
        "29": "<p><strong>rĕʾû kî YHWH nātan lākem haššabbāt</strong>: 'See that YHWH has given you the Sabbath.' The Sabbath is framed as a gift (<em>nātan</em> = to give) before it is a law. The command to remain in one's place (<em>šĕbû ʾîš taḥtāyw</em>) on the Sabbath is the first formal Sabbath stipulation in the narrative, anticipating the later prohibitions against kindling fire (35:3) and carrying loads (Jer 17:21-22).</p>",
        "30": "<p><strong>wayyišbĕtû hāʿām bayyôm haššĕbîʿî</strong>: 'the people rested on the seventh day.' The verb <em>šāḇat</em> (from which <em>šabbāt</em> derives) means 'to cease/desist/rest from activity.' The Sabbath rest is cessation modeled on YHWH's own rest after creation (Gen 2:2-3: <em>wayyišbōt</em>, 'and he rested'). The covenant community's Sabbath participates in the Creator's rest.</p>",
        "31": "<p><strong>man</strong>: the name is confirmed. <strong>zera gad lāban</strong> (like coriander seed, white) and <strong>ṭaʿmô kĕṣappîḥît bidbāš</strong> (its taste like wafers in honey). Two similes: visual (white like coriander seed) and gustatory (sweet like honey). The honey simile evokes the promised land flowing with milk and honey — the manna is a foretaste of the land's abundance. Num 11:8 adds that grinding it produced an oil-cake taste.</p>",
        "32": "<p><strong>ʾōmer hāmĕlēʾ</strong>: 'a full omer.' YHWH commands a jar of manna to be kept (<em>hinnîaḥ</em>) for generations to see <em>ʾet-haleḥem ʾăšer heʾakaltî ʾetkem</em> ('the bread with which I fed you in the wilderness'). The memorial function: the manna jar placed in the ark (Heb 9:4) connects this preservation command to the tabernacle's most holy space, making the manna a permanent witness to YHWH's wilderness provision.</p>",
        "33": "<p><strong>ṣinnĕṣenet</strong>: a jar or pot — a hapax legomenon, the only occurrence of this word in the OT. The object's uniqueness mirrors the uniqueness of its contents. Aaron places it 'before YHWH' (<em>lipnê YHWH</em>), the phrase used for the sanctuary's inner presence. The manna jar's placement anticipates the ark not yet built — an anachronism the narrator resolves by noting (v34) the specific ark to which it refers.</p>",
        "34": "<p>Aaron places the manna before <em>hāʿēdut</em> (the Testimony) — a prospective act. The Testimony refers to the stone tablets to be placed in the ark (Exod 25:16; 40:20), not yet given at this point in the narrative. The narrator projects forward from the Sinai covenant to explain the placement. The manna jar sits in the ark alongside the covenant documents — provision paired with commandment, grace alongside law.</p>",
        "35": "<p><strong>wĕbĕnê yiśrāʾēl ʾākelû ʾet-hammān arbaʿîm šānāh</strong>: 'the children of Israel ate the manna forty years.' The manna provision spans the entire wilderness generation, ending only when they eat the produce of Canaan (Josh 5:12). The forty-year continuity establishes the manna as the wilderness-period bread in toto. <em>ʿAd bôʾām ʾel-qĕṣēh ʾereṣ Kĕnaʿan</em> ('until they came to the edge of the land of Canaan') — provision ends at the boundary of fulfillment.</p>",
        "36": "<p><strong>wĕhāʿōmer ʿăśîrît hāʾêpāh hûʾ</strong>: 'and the omer is one-tenth of an ephah.' The parenthetical definition closes the manna chapter with a metrological note. An ephah is approximately 22 liters; an omer is thus about 2.2 liters. The precision serves the narrative's concern with exact provision: exactly enough, measured and calibrated, is YHWH's characteristic mode of grace in the wilderness.</p>"
    },
    "17": {
        "1": "<p><strong>ʿal pî YHWH</strong>: 'according to the mouth/command of YHWH' — the wilderness itinerary formula indicating each movement is divinely directed. The phrase recurs throughout Num 9:18-23 to describe the cloud's role in determining encampment and movement. <em>Rĕpîdîm</em> is the final station before Sinai; its place in the itinerary makes it the last test before the great covenant encounter.</p>",
        "2": "<p><strong>wayyārēb hāʿām ʿim-mōšeh</strong>: 'the people quarreled with Moses.' The verb <em>rîb</em> is a legal term — it denotes filing a lawsuit, bringing a formal complaint. The same root underlies the covenant lawsuit (<em>rîb</em>) structure in the Prophets (Mic 6:2; Hos 4:1) where YHWH brings charges against Israel. Here Israel files a lawsuit against their deliverer. Moses's counter-question reframes the dispute: quarreling with Moses is testing (<em>nāsāh</em>) YHWH.</p>",
        "3": "<p><strong>lāmāh zeh heʿĕlîtānû mimmîṣrāyim lĕhamît ʾōtî</strong>: 'why have you brought us up from Egypt to kill me?' The accusative <em>ʾōtî</em> (me) is singular — each individual speaker levels the complaint personally. The pattern of accusation — Exodus as a journey to death rather than life — repeats from 14:11 and 16:3. Each complaint ignores prior deliverance and focuses exclusively on present privation.</p>",
        "4": "<p><strong>mā ʾeʿĕśeh lāʿām hazzeh</strong>: 'What shall I do with this people?' Moses's cry to YHWH is the mediator's lament caught between a rebellious people and the God they provoke. <em>ʿÔd meʿaṭ ûsĕqālunî</em> ('they are almost ready to stone me') — the hostility of the wilderness congregation threatens Moses personally. The mediator's vulnerability is structural: he bears the people's anger while interceding on their behalf.</p>",
        "5": "<p><strong>ʿăbōr lipnê hāʿām</strong>: 'Pass on before the people.' YHWH directs Moses to take elders as witnesses — the provision of water is to occur publicly before credible witnesses. Taking the staff (<em>maṭṭeh</em>) used at the Nile connects this water-miracle to the Exodus plagues: the same instrument of judgment against Egypt becomes the instrument of provision for Israel.</p>",
        "6": "<p><strong>hinnĕnî ʿōmēd lĕpānêkā šām ʿal-haṣṣûr bĕḥōrēb wĕhikkîtā baṣṣûr</strong>: 'I will stand before you there on the rock at Horeb, and you shall strike the rock.' The preposition <em>ʿal</em> (on/upon) with <em>ʿāmad</em> (to stand) means YHWH positions himself <em>on</em> the rock. The blow Moses strikes falls on the rock where YHWH stands — substitutionary solidarity. YHWH absorbs the stroke meant for covenant-breaking Israel. <em>Ûyāṣĕʾû mimmennû mayim</em>: 'and water shall come out of it' — not from the strike alone but from YHWH's presence on the rock. Paul's identification 'the Rock was Christ' (1 Cor 10:4) names the one who stood there to be struck so that water — life — flows for his people.</p>",
        "7": "<p><strong>Massāh ûMĕrîbāh</strong>: Two place-names derived from the events: <em>Massāh</em> from <em>nāsāh</em> (to test/try) — a place of testing; <em>Mĕrîbāh</em> from <em>rîb</em> (to contend/quarrel) — a place of contention. The double name memorializes both the people's fault and YHWH's response. Ps 95:8 ('Do not harden your hearts as at Meribah, as on the day at Massah in the wilderness') is cited in Heb 3:8-11 as a warning against abandoning faith.</p>",
        "8": "<p><strong>wayyābōʾ ʿĂmālēq wayyillāḥem ʿim Yiśrāʾēl bĕRĕpîdîm</strong>: 'Amalek came and fought against Israel at Rephidim.' The Amalekites make their first narrative appearance here; they will become Israel's archetypal enemy (Gen 36:12; Num 24:20; Deut 25:17-19). Their attack is particularly condemned in Deut 25:18 because they attacked 'from the rear, all who were faint and weary' — they preyed on the vulnerable.</p>",
        "9": "<p><strong>Yĕhôšuaʿ</strong> (Joshua) — first narrative appearance by this name (his birth name was <em>Hôšēaʿ</em>, Num 13:16; Moses renamed him). <em>Yĕhôšuaʿ</em> = YHWH saves/delivers — a theophoric name. The military commander and the intercessor are paired — Joshua's sword and Moses's raised hands are not alternatives but complements in the theology of holy war.</p>",
        "10": "<p>Joshua implements Moses's command; the battle begins. The narrative shifts between the valley and the hilltop to show the connection between the earthly fight and the heavenly intercession. Hur — paired with Aaron — appears here and in 24:14 (holding authority during Moses's absence on Sinai). The three-man support structure mirrors the later pattern of multiple elders sustaining a single leader's ministry.</p>",
        "11": "<p><strong>kaʾăšer yārîm mōšeh yādô wĕgābar Yiśrāʾēl</strong>: 'whenever Moses raised his hand Israel prevailed.' Moses's raised hands signal sustained prayer, not magical causation. The <em>qal</em> participle indicates continuous action. When his hands drop, Amalek prevails — the intercession must be unbroken. Raising hands (<em>nāśāʾ yādayim</em>) was the posture of oath and prayer (Gen 14:22; Ps 28:2; 134:2).</p>",
        "12": "<p><strong>wîdê mōšeh kĕbēdîm</strong>: 'Moses's hands were heavy.' The word <em>kābēd</em> (heavy) is the same root as <em>kābôd</em> (glory) — glory is weight. The hands too heavy to raise enact the physical analogy of weighted prayer. Aaron and Hur hold up Moses's hands — the community sustains the intercessor. The support of Moses's arms is a picture of corporate intercession: the mediator does not pray alone but is upheld by the community he represents.</p>",
        "13": "<p><strong>wayyaḥălōš Yĕhôšuaʿ ʾet ʿĂmālēq</strong>: 'Joshua subdued Amalek.' The verb <em>ḥālaš</em> (to weaken/prostrate) conveys decisive defeat. <em>Lĕpî ḥāreb</em> (literally 'to the mouth of the sword') is the standard idiom for total military defeat — the sword's edge consumes. The coordinated victory — Joshua's sword below, Moses's hands above — models holy war theology: YHWH fights from his throne while his people engage in the valley.</p>",
        "14": "<p><strong>kĕtōb zōʾt zikkārôn basēper</strong>: 'Write this as a memorial in the book.' The first explicit command to write in the Torah. <em>Zikkārôn</em> (memorial record) from <em>zākar</em> (to remember) — the written record ensures preservation beyond the witnessing generation. <em>Bāsēper</em> (in the book) with a definite article suggests a specific document, perhaps the beginning of the Mosaic literary tradition. The command to remember and erase Amalek's name provides the framework for the Purim narrative (Esther) and eschatological battle themes.</p>",
        "15": "<p><strong>YHWH Nissî</strong>: 'YHWH is my banner/standard.' Moses builds an altar and names it — the practice of naming altars to commemorate YHWH's acts recurs in the patriarchal narratives (Gen 33:20; 35:7). <em>Nēs</em> (banner, standard) is the military insignia around which troops rally; naming YHWH as the <em>nēs</em> declares him the standard under which Israel fights. The same word is used in Isa 11:12: YHWH will raise a banner (<em>nēs</em>) for the nations.</p>",
        "16": "<p><strong>yād ʿal kēs YH milḥāmāh laYHWH baʿĂmālēq middōr dōr</strong>: 'A hand is on the throne of YH — war to YHWH against Amalek from generation to generation.' The phrase is compressed and debated. <em>Kēs</em> may be contracted from <em>kissēʾ</em> (throne). <em>YH</em> is the shortened divine name, perhaps because the full name is withheld while Amalek's name exists. The perpetual warfare (<em>middōr dōr</em> = from generation to generation) establishes the theological framework for Saul's failure in 1 Sam 15 and the eschatological defeat of evil's final representative.</p>"
    },
    "18": {
        "1": "<p><strong>Yitrô kōhēn Midyān ḥōtēn Mōšeh</strong>: 'Jethro the priest of Midian, Moses's father-in-law.' Jethro is introduced by his religious title (<em>kōhēn</em> = priest) and his familial relationship. As <em>kōhēn</em> of Midian, he is a non-Israelite religious official whose knowledge of YHWH (v.11) comes from prior revelation and now from hearing the news of the Exodus. The Gentile priest is the surprising vehicle of governance wisdom in this chapter.</p>",
        "2": "<p><strong>ʾaḥar šillûḥêhā</strong>: 'after her sending away/dismissal.' This parenthetical note indicates Moses had sent Zipporah back to Jethro at some point. <em>Šillûḥîm</em> (dismissal, sending away) uses the same root as divorce terminology (Deut 24:1, 3), though here it simply means he sent her home. Jethro now returns her to Moses, restoring the family unit before the Sinai encounter.</p>",
        "3": "<p><strong>Gēršōm</strong>: from <em>gēr šām</em> (a sojourner there) — Moses's naming theology embedded in his son's name. The <em>gēr</em> (resident alien/sojourner) is the central social category in the Exodus narrative: the law will repeatedly ground concern for the sojourner in Israel's own sojourn experience (22:21; 23:9; Lev 19:33-34). The name carries the Exodus's social ethic.</p>",
        "4": "<p><strong>ʾĔlîʿezer</strong>: 'my God is help' — <em>ʾĔlî</em> (my God) + <em>ʿezer</em> (help), the same root as in <em>ʿezer kĕnegdô</em> (Gen 2:18). The specific rescue cited: <em>wayyaṣṣilēnî mēḥereb parʿōh</em> ('he delivered me from Pharaoh's sword'). The <em>hiphil</em> of <em>nāṣal</em> (to rescue/deliver) is key Exodus vocabulary for YHWH's saving action. The name commemorates personal deliverance that precedes and anticipates the national deliverance.</p>",
        "5": "<p><strong>ʾel-hāhār ʾĕšer hûʾ ḥōneh šām</strong>: 'to the mountain where he was encamped.' The burning bush mountain (Horeb/Sinai, 3:1) is the destination toward which the whole wilderness journey has been oriented. Jethro comes to meet Moses at the mountain of God — the site of prior revelation is the site of this reunion. The movement brings the Gentile priest to the sacred center of YHWH's revelation to Israel.</p>",
        "6": "<p>Jethro sends word ahead of his coming — the proper protocol for approaching a leader. <em>ʾĂnî ḥōtĕnĕkā Yitrô bāʾ ʾēlêkā</em>: 'I, your father-in-law Jethro, am coming to you.' The self-identification with relationship category (<em>ḥōtēn</em> = father-in-law) signals the domestic register of the visit — family reunion before political consultation.</p>",
        "7": "<p><strong>wayyēṣēʾ mōšeh liqrāʾt ḥōtĕnô wayyištaḥû wayyiššaq lô</strong>: 'Moses went out to meet his father-in-law, bowed down, and kissed him.' Three verbs capture the full protocol of respectful greeting: going out to meet (<em>liqrāʾt</em> = a formal reception), prostrating (<em>šāḥāh</em>, the same verb used of worship), and kissing (<em>nāšaq</em>). The greeting is the full covenant-community hospitality gesture, parallel to Abraham meeting the three visitors (Gen 18:2).</p>",
        "8": "<p><strong>wayyĕsapper Mōšeh lĕḥōtĕnô ʾēt kol-ʾăšer ʿāśāh YHWH</strong>: 'Moses told his father-in-law all that YHWH had done.' The verb <em>sāpar</em> (to count/recount/tell) is the same root as <em>sēper</em> (book/document) — telling is a form of inscription. The narrative covers: YHWH's acts against Pharaoh and Egypt; all the hardship (<em>tĕlāʾāh</em>) along the way; and how YHWH had delivered them. Moses's recounting is an act of covenant witness — he testifies to the Gentile priest.</p>",
        "9": "<p><strong>wayyiḥad Yitrô</strong>: 'Jethro rejoiced.' The verb <em>ḥādāh</em> (to rejoice/be glad) is relatively rare; it appears in the Psalms and here. Jethro's joy is specified: <em>ʿal kol-haṭṭôbāh</em> (over all the good) that YHWH had done for Israel. The affective response to the news of redemption is joy — the appropriate and full response to the gospel of deliverance.</p>",
        "10": "<p><strong>Bārûk YHWH ʾăšer hiṣṣîl ʾetkem</strong>: 'Blessed be YHWH who delivered you.' Jethro's benediction is a <em>berakah</em> formula — the standard blessing-formula that acknowledges YHWH as the source of good. The double <em>miyyad</em> (from the hand of) emphasizes comprehensive rescue: from Egyptian power as a system and from Pharaoh's personal power. The Gentile priest speaks the covenant community's liturgy of gratitude.</p>",
        "11": "<p><strong>ʿattāh yādaʿtî kî gādôl YHWH mikkol-hāʾĕlōhîm</strong>: 'Now I know that YHWH is greater than all the gods.' Jethro's confession is the theological climax of the chapter. <em>ʿAttāh yādaʿtî</em> (now I know) — the experiential knowledge formula, knowledge through hearing testimony. The comparative <em>gādôl mikkol-hāʾĕlōhîm</em> (greater than all the gods) asserts YHWH's superiority. <em>Kî baddābār ʾăšer zādû ʿălêhem</em> ('for in the thing in which they acted arrogantly') specifies the basis: Egypt's gods sponsored Egyptian arrogance, and YHWH defeated them at every point. The Gentile priest confesses what Israel often forgets.</p>",
        "12": "<p><strong>wayyiqqaḥ Yitrô ḥōtēn Mōšeh ʿōlāh ûzĕbāḥîm lēʾlōhîm</strong>: 'Jethro brought a burnt offering and sacrifices to God.' <em>ʿÔlāh</em> (burnt offering — wholly consumed, ascending to God) and <em>zĕbāḥîm</em> (peace/fellowship offerings — shared between God and worshippers) together constitute a complete worship act. Aaron and all the elders of Israel join the meal — Jethro's sacrifices are the occasion for a covenant meal that includes the leadership of Israel. The Gentile priest participates in Israel's liturgy.</p>",
        "13": "<p><strong>wayyēšeb Mōšeh lišpōṭ ʾet-hāʿām ... min-habbōqer ʿad-hāʿāreb</strong>: 'Moses sat to judge the people ... from morning until evening.' The verb <em>šāpaṭ</em> (to judge, decide, govern) covers arbitration, rule-declaration, and case adjudication. The phrase <em>min-habbōqer ʿad-hāʿāreb</em> (from morning until evening) captures the unsustainability of one-person governance — Moses as sole judge creates a system that consumes its most gifted member.</p>",
        "14": "<p><strong>wayyarʾ ḥōtēn Mōšeh ʾēt kol-ʾăšer hûʾ ʿōśeh lāʿām</strong>: 'Moses's father-in-law saw everything he was doing for the people.' Jethro's observation is the outsider's diagnostic perspective. <em>Maddûaʿ ʾattāh yōšēb lĕbaddekā</em> ('why do you sit alone?') — <em>baddekā</em> means 'by yourself alone.' The problem is systemic, not a matter of Moses's dedication; the system's architecture is defective.</p>",
        "15": "<p><strong>kî-yābōʾ ʾēlay hāʿām lidrōš ʾĕlōhîm</strong>: 'because the people come to me to inquire of God.' The verb <em>dāraš</em> (to seek/inquire) is the technical term for consulting an oracle or judicial authority. <em>Lidrōš ʾĕlōhîm</em> (to inquire of God) — Moses's role is not merely legal arbiter but mediator of divine decision. Every case is framed as a consultation with God, which explains both the burden and the bottleneck.</p>",
        "16": "<p><strong>kî yihyeh lāhem dābār bāʾ ʾēlay ûšāpaṭtî bên ʾîš ûbên rēʿēhû</strong>: 'when they have a dispute they come to me, and I judge between a man and his neighbor.' Moses also teaches the decrees and laws of God — the judge is simultaneously teacher and case-arbiter. The dual function (teaching and adjudicating) is the foundation of the Levitical-priestly and later rabbinic judicial role.</p>",
        "17": "<p><strong>lōʾ-ṭôb haddābār ʾăšer ʾattāh ʿōśeh</strong>: 'the thing you are doing is not good.' Jethro's assessment uses the emphatic construction: <em>nābōl tibbōl gam-ʾattāh gam-hāʿām hazzeh</em> — 'you will surely wear out, both you and this people.' <em>Nābōl tibbōl</em> is the Qal infinitive absolute + imperfect: 'wearing out you will wear out.' The verb <em>nābal</em> (to wither/wilt/wear out) connects physical exhaustion with a kind of organizational foolishness.</p>",
        "18": "<p><strong>nābōl tibbōl</strong>: the emphatic infinitive absolute confirms inevitability. <em>Kî kābēd mimmĕkā haddābār</em> ('the thing is too heavy for you') — <em>kābēd</em> (heavy) recurs from 17:12 (Moses's heavy hands). The same heaviness that required Aaron and Hur's support in battle now requires delegation in governance. Physical and organizational weight are parallel problems with parallel solutions: delegation and support structures.</p>",
        "19": "<p><strong>ʾĕhyeh ʿimmāk lēʾlōhîm</strong>: 'be to God for the people.' Moses's role is defined as the people's representative before God. The phrase uses <em>ʾĕhyeh</em> (the I AM name) in a human application — Moses functions as the mediator of the I AM's presence. He stands between people and God: bringing their cases upward, bringing God's statutes and decisions downward. This mediatorial role is the OT pattern for the high priest and ultimately for Christ (Heb 9:24).</p>",
        "20": "<p><strong>wĕhizahartāh ʾethem ʾet-haḥuqqîm wĕʾet-hattôrōt wĕhôdaʿtā lāhem ʾet-hadderek</strong>: Four vocabulary items: <em>ḥuqqîm</em> (statutes — fixed, often cultic decrees), <em>tôrôt</em> (plural of <em>tôrāh</em> — instructions, from <em>yārāh</em> to shoot/direct), <em>hadderek</em> (the way — the halakic pattern), and <em>hammaʿăśeh</em> (the work/deeds). The judicial role is inseparable from the teaching role: judges must first be teachers of the law they administer. <em>Yārāh</em> (the root of <em>tôrāh</em>) means to shoot/aim/direct — Torah is divine direction for the path of life.</p>",
        "21": "<p><strong>ʾanšê ḥayil yirĕʾê ʾĕlōhîm ʾanšê ʾĕmet śōnĕʾê beṣaʿ</strong>: four qualifications for judges — 'capable men, God-fearing, men of truth, haters of unjust gain.' <em>Ḥayil</em> (capable/competent — the word for virtue in Ruth 3:11 and Prov 31:10) covers intellectual and practical competence. <em>Yirĕʾê ʾĕlōhîm</em> (God-fearing) is the foundational orientation — judicial wisdom begins with the fear of YHWH (Prov 1:7). <em>ʾĔmet</em> (truth/faithfulness — both cognitive and moral accuracy). <em>Śōnĕʾê beṣaʿ</em> (haters of dishonest gain/bribery) — incorruptibility. This fourfold profile becomes the standard for Israelite leadership (Deut 1:13-17; 16:18-20).</p>",
        "22": "<p><strong>kol-haddābār haggādōl yabiʾû ʾēlêkā wĕkol-haddābār haqqāṭōn yišpĕṭû hēm</strong>: 'every great matter they shall bring to you, but every small matter they shall judge themselves.' The graduated judicial hierarchy: minor cases decided locally; significant cases escalated to Moses. <em>Gādôl</em> and <em>qāṭōn</em> become the standing terms for case-scale in Israelite jurisprudence (Deut 1:17). This architecture anticipates the Sanhedrin's three-tiered system (courts of 3, 23, and 71).</p>",
        "23": "<p><strong>wĕṣiwwĕkā ʾĕlōhîm wĕyākaltā ʿămōd</strong>: 'and God so commands you, you will be able to stand.' Jethro conditions the entire plan on divine sanction — the reform is not his imposition but must be validated by covenant authority. Moses does not implement immediately; the chapter ends with Moses doing as Jethro said, but the assumption is that YHWH's approval is sought. Governance wisdom is subsumed under covenant authority.</p>",
        "24": "<p><strong>wayyišmaʿ Mōšeh lĕqôl ḥōtĕnô wayyaʿas kōl ʾăšer ʾāmar</strong>: 'Moses listened to his father-in-law's voice and did everything he said.' The verb <em>šāmaʿ</em> (to hear/obey) carries both meanings. Moses's willingness to be instructed by a Gentile priest — taking counsel from outside the covenant community — demonstrates the humility described in Num 12:3 ('Moses was very meek'). Wisdom is not exclusive to the covenant community; YHWH's common grace distributes organizational insight broadly.</p>",
        "25": "<p><strong>šārê ʾălāpîm šārê mēʾôt šārê ḥămiššîm wĕšārê ʿăśārōt</strong>: 'commanders of thousands, commanders of hundreds, commanders of fifties, commanders of tens.' The decimal hierarchy creates a scalable governance structure. The word <em>śar</em> (commander/prince/leader) is used for both military commanders and civil leaders. The decimal organization mirrors the census structure of Num 1 and the military organization of Deuteronomy. Governance and military command share the same hierarchical architecture.</p>",
        "26": "<p><em>ʾEt-haddābār haqqāšeh</em> (the hard/difficult matter) — <em>qāšeh</em> (hard, stiff, difficult) is used of hard labor in Egypt (1:14) and the hardened heart of Pharaoh (7:3). The difficult cases require concentrated attention that the Exodus itself required. The gradation of difficulty structures legal access to Moses: only the genuinely complex reaches the covenant mediator.</p>",
        "27": "<p><strong>wayyĕšallaḥ Mōšeh ʾet-ḥōtĕnô wayyēlek lô ʾel-ʾarṣô</strong>: 'Moses sent his father-in-law away, and he went to his own land.' Jethro departs before Sinai — he does not receive the covenant directly (though Num 10:29-32 suggests he or his son Hobab may have traveled with Israel). The Gentile priest who confessed YHWH's supremacy, offered sacrifice, participated in the covenant meal, and reformed Israel's judicial system returns home. His contribution is complete; the Sinai narrative awaits.</p>"
    }
}

def main():
    existing = load_comm('mkt-original', 'exodus')
    merge_comm(existing, EXODUS_ORIGINAL)
    save_comm('mkt-original', 'exodus', existing)
    for ch in ['16', '17', '18']:
        vv = existing.get(ch, {})
        print(f'  ch{ch}: {len(vv)} verse(s) with original commentary')

if __name__ == '__main__':
    main()
